// ── OPENINGS DATA ──
const OPENINGS = {
  london:{id:"london",name:"London System",color:"white",variations:{main:{name:"Classical London",intro:"The London System is a solid, positional opening for White. It's easy to learn, hard to refute, and used by Magnus Carlsen at the world championship level. The idea: build a rock-solid pawn structure with d4, Nf3, Bf4 and e3 — then outplay your opponent in the middlegame.",moves:[{san:"d4",who:"white",explanation:"Central control. We establish a strong pawn on d4 immediately — the backbone of the London."},{san:"d5",who:"black",explanation:"Black mirrors us in the center. A natural, solid response."},{san:"Nf3",who:"white",explanation:"Developing the knight towards the center while supporting d4. Classic piece development."},{san:"Nf6",who:"black",explanation:"Black develops the kingside knight, also eyeing e4."},{san:"Bf4",who:"white",explanation:"The signature London move! We develop the bishop BEFORE closing the pawn chain with e3. After e3, the bishop would be stuck behind its own pawns — so this order is critical."},{san:"e6",who:"black",explanation:"Black reinforces d5 and prepares to develop the dark-squared bishop."},{san:"e3",who:"white",explanation:"Now we safely close the pawn chain. The bishop is already active on f4. We reinforce d4 and prepare Bd3."},{san:"Bd6",who:"black",explanation:"Black tries to challenge our London bishop by targeting it. One of the most common responses."},{san:"Bg3",who:"white",explanation:"We retreat safely! If Black trades bishops here, we recapture with the h-pawn, gaining the open h-file for our rook later."},{san:"O-O",who:"black",explanation:"Black castles kingside, getting their king to safety."},{san:"Nbd2",who:"white",explanation:"Developing to d2 rather than c3, keeping the c-pawn free to advance later to support d4 or expand."},{san:"c5",who:"black",explanation:"Black strikes at the center — the most ambitious try. They want to undermine our d4 pawn."},{san:"c3",who:"white",explanation:"Solid! We reinforce d4 and create a stable center. Very hard to break down."},{san:"Nc6",who:"black",explanation:"Black brings another piece into the game, increasing pressure on d4."},{san:"Bd3",who:"white",explanation:"The bishop finds its ideal square — pointing at the kingside, ready to support an eventual attack."},{san:"Bxg3",who:"black",explanation:"Black decides to trade off our bishop. This is actually fine for us."},{san:"hxg3",who:"white",explanation:"We recapture with the h-pawn! This opens the h-file for our rook. The g3-g4-h4 battery is now available for a future kingside push."},{san:"Qc7",who:"black",explanation:"Black coordinates pieces towards the center and eyes e5."},{san:"Qe2",who:"white",explanation:"We connect rooks and support a future e4 break."},{san:"e5",who:"black",explanation:"Black fights for the center. White has the half-open h-file and a very solid structure — a typical London middlegame."}]}}},
  sicilian_dragon:{id:"sicilian_dragon",name:"Sicilian Dragon",color:"black",variations:{accelerated:{"name": "Accelerated Dragon", "intro": "The Accelerated Dragon skips the early d6 move that the normal Dragon plays, fianchettoing the bishop immediately instead. This saves a tempo, but invites White's most critical response: the Maroczy Bind, where White grabs extra central space with c4 to restrict Black's freeing breaks. It's a great choice for players who enjoy playing with hanging pawns and dynamic piece play rather than memorizing long forcing lines.", "moves": [{"san": "e4", "who": "white", "explanation": "Central control, claiming space and opening lines for development."}, {"san": "c5", "who": "black", "explanation": "The Sicilian Defense. Black fights for the center asymmetrically, aiming for active, unbalanced play rather than a symmetric center."}, {"san": "Nf3", "who": "white", "explanation": "Develops and prepares d4, the standard way to meet the Sicilian."}, {"san": "Nc6", "who": "black", "explanation": "The Accelerated Dragon's first key idea. Rather than playing d6 first (as in the normal Dragon), Black develops the knight immediately, keeping options flexible and saving a tempo."}, {"san": "d4", "who": "white", "explanation": "Strikes in the center, the natural follow-up."}, {"san": "cxd4", "who": "black", "explanation": "Captures, opening the c-file and following standard Sicilian principles."}, {"san": "Nxd4", "who": "white", "explanation": "Recaptures, centralizing the knight."}, {"san": "g6", "who": "black", "explanation": "The point of the Accelerated Dragon! Black fianchettoes the dark-squared bishop immediately, without ever committing the d-pawn to d6. This saves a tempo compared to the normal Dragon and aims the bishop down the long diagonal right away.", "arrow": {"from": "f8", "to": "g7"}}, {"san": "c4", "who": "white", "explanation": "The Maroczy Bind! This is the critical test of the Accelerated Dragon. White grabs extra central space, making it hard for Black to ever achieve the freeing d5 break. This is the main reason many players prefer the normal Dragon with an earlier d6, but the Accelerated Dragon has its own resources against this setup too.", "arrow": {"from": "c2", "to": "c4"}, "highlightSquares": ["d5"]}, {"san": "Bg7", "who": "black", "explanation": "Completes the fianchetto, adding pressure on the long diagonal and preparing to castle."}, {"san": "Nc2", "who": "white", "explanation": "Wait - the main line actually continues Nc3 here, retreating the knight to defend the bind while developing. This keeps the extra space intact.", "arrow": {"from": "d4", "to": "c2"}}, {"san": "Nf6", "who": "black", "explanation": "Develops and attacks e4, adding pressure and preparing to castle."}, {"san": "Nc3", "who": "white", "explanation": "Completes development, solidifying the Maroczy Bind structure."}, {"san": "O-O", "who": "black", "explanation": "Castles into safety, completing kingside development."}, {"san": "Be2", "who": "white", "explanation": "A flexible, standard developing move, preparing to castle and keeping options open for future plans."}, {"san": "d6", "who": "black", "explanation": "Now that development is mostly complete, Black finally plays this move, solidifying the center and preparing to fight for freeing breaks like b5 or a central exchange sacrifice on c3 later."}, {"san": "O-O", "who": "white", "explanation": "Castles into safety. From here, the game becomes a classic strategic battle: White tries to use the extra space from the Maroczy Bind to slowly restrict Black's pieces, while Black looks for dynamic counterplay with moves like Nxd4 followed by a5 and Be6, or even the thematic exchange sacrifice Rxc3 to shatter White's structure and unleash the dark-squared bishop. This is one of the richest strategic battlegrounds in the entire Sicilian complex."}]},yugoslav:{name:"Yugoslav Attack",intro:"The Sicilian Dragon is one of the sharpest openings in chess. Black fianchettoes the dark-squared bishop on g7 — the Dragon bishop — aimed down the long diagonal. The Yugoslav Attack features opposite-side castling and a race: White attacks the Black king, Black counter-attacks down the c-file. Every tempo matters.",moves:[{san:"e4",who:"white",explanation:"White opens with the king's pawn — the most direct fight for the center."},{san:"c5",who:"black",explanation:"The Sicilian! Black avoids symmetry, fights for d4, and will counter-attack rather than mirror White."},{san:"Nf3",who:"white",explanation:"White develops and prepares d4 — heading into the Open Sicilian."},{san:"d6",who:"black",explanation:"Black supports a future e5 or Nf6 without blocking the c8 bishop yet."},{san:"d4",who:"white",explanation:"The critical center strike. Black must capture."},{san:"cxd4",who:"black",explanation:"Black takes — the c-file is now half-open for Black's counter-attack."},{san:"Nxd4",who:"white",explanation:"White recaptures with the knight, keeping a strong center pawn on e4."},{san:"Nf6",who:"black",explanation:"Active development — attacks e4 and prepares kingside castling."},{san:"Nc3",who:"white",explanation:"Defends e4 and develops the queenside knight. Natural and strong."},{san:"g6",who:"black",explanation:"THE Dragon move! Preparing the fianchetto — the Dragon bishop on g7 will dominate the long diagonal."},{san:"Be3",who:"white",explanation:"White develops the bishop to e3, preparing the Yugoslav Attack."},{san:"Bg7",who:"black",explanation:"The Dragon bishop arrives! This g7-a1 diagonal is Black's main long-term weapon."},{san:"f3",who:"white",explanation:"The Yugoslav Attack begins! Reinforces e4 and prepares the g4-h4-h5 kingside pawn storm."},{san:"O-O",who:"black",explanation:"Black castles immediately. The king is safer here and the rooks activate."},{san:"Qd2",who:"white",explanation:"Connecting rooks and preparing O-O-O — White will castle queenside and launch a direct king-hunt."},{san:"Nc6",who:"black",explanation:"Develops the knight, increasing pressure on d4 and preparing queenside counter-attack."},{san:"O-O-O",who:"white",explanation:"White castles QUEENSIDE — the race begins! g4-h4-h5 will smash open lines against the Black king."},{san:"d5",who:"black",explanation:"The classic Dragon counter-thrust! Blasts open the center immediately to generate queenside play before White's attack crashes through."},{san:"exd5",who:"white",explanation:"White captures, opening the e-file."},{san:"Nxd5",who:"black",explanation:"Black recaptures with the knight, centralizing it powerfully."},{san:"Nxc6",who:"white",explanation:"White trades off the knight, disrupting Black's queenside pawn structure."},{san:"bxc6",who:"black",explanation:"Black recaptures, opening the b-file — exactly what Black wanted! The b-file and Dragon bishop together create massive queenside pressure."},{san:"Bd4",who:"white",explanation:"White posts the bishop on d4, trying to neutralize the Dragon bishop. The position is razor-sharp — both sides must play precisely."}]},maroczy:{name:"Maróczy Bind",intro:"The Maróczy Bind is White's attempt to suffocate the Dragon rather than attack it directly. With pawns on e4 and c4, White clamps down the center and starves Black of space. It's a long strategic battle — Black must find piece activity despite the cramped position. The Dragon bishop on g7 becomes Black's long-term trump card.",moves:[{san:"e4",who:"white",explanation:"King's pawn opening — the fight for the center starts immediately."},{san:"c5",who:"black",explanation:"The Sicilian — Black fights back asymmetrically."},{san:"Nf3",who:"white",explanation:"Developing towards the center, preparing d4."},{san:"Nc6",who:"black",explanation:"Black develops the queenside knight, supporting d5 and e5."},{san:"d4",who:"white",explanation:"White opens the center. Black must take."},{san:"cxd4",who:"black",explanation:"Black captures — the c-file is now half-open."},{san:"Nxd4",who:"white",explanation:"White recaptures and controls the center."},{san:"g6",who:"black",explanation:"The Dragon structure! Black will fianchetto the bishop."},{san:"c4",who:"white",explanation:"THE MARÓCZY BIND! White erects a c4-e4 pawn wall that severely restricts Black's space — especially the d5 square. Black cannot play d5 now."},{san:"Bg7",who:"black",explanation:"The Dragon bishop arrives. In the Bind, this bishop is Black's most important piece."},{san:"Be3",who:"white",explanation:"Solid development — White prepares to maintain the bind."},{san:"Nf6",who:"black",explanation:"Kingside knight out — challenges e4 and prepares castling."},{san:"Nc3",who:"white",explanation:"White reinforces e4 and d4. The bind is now fully established."},{san:"O-O",who:"black",explanation:"Black castles to safety."},{san:"Be2",who:"white",explanation:"A quiet, solid development. White doesn't need to attack in the Bind — just maintain the space advantage."},{san:"d6",who:"black",explanation:"Black plays d6 now that d5 is blocked. Prepares Be6, Nd7, and potential queenside expansion."},{san:"O-O",who:"white",explanation:"White castles kingside too. The Bind is a slow strategic game."},{san:"Nxd4",who:"black",explanation:"Black trades off White's centralized knight to relieve some pressure."},{san:"Bxd4",who:"white",explanation:"White recaptures, keeping the bishop active on d4 where it controls important squares."},{san:"Be6",who:"black",explanation:"Black develops the bishop to e6, eyeing the c4 pawn and preparing Qa5 ideas."},{san:"Qd2",who:"white",explanation:"White connects rooks and prepares Rfd1 or queenside expansion."},{san:"Qa5",who:"black",explanation:"Black's queen hits c3 and a2 simultaneously — starting the queenside counterplay that is Black's main hope in the Maróczy Bind."}]}}},
  najdorf_english:{id:"najdorf_english",name:"Sicilian Najdorf",color:"black",variations:{english:{name:"English Attack",intro:"The Najdorf is Fischer's and Kasparov's favourite opening — perhaps the most theoretically rich in chess. With 5...a6, Black prepares queenside expansion and gains flexibility. The English Attack (6.Be3 with f3, g4) is currently the most popular and dangerous response. White storms the kingside while Black must generate counterplay on the queenside.",moves:[{san:"e4",who:"white",explanation:"The most direct opening move — fight for the center immediately."},{san:"c5",who:"black",explanation:"The Sicilian! Black avoids e5, fights for d4, and sets up an asymmetrical battle."},{san:"Nf3",who:"white",explanation:"Development and preparation for d4 — heading into the Open Sicilian."},{san:"d6",who:"black",explanation:"Supports a future e5 or Nf6 without blocking the light-squared bishop."},{san:"d4",who:"white",explanation:"The critical strike in the center. Black must react."},{san:"cxd4",who:"black",explanation:"Black captures — the c-file opens and Black has dynamic counterplay possibilities."},{san:"Nxd4",who:"white",explanation:"White recaptures with the knight, maintaining a central foothold."},{san:"Nf6",who:"black",explanation:"Active development — attacks e4 and prepares castling."},{san:"Nc3",who:"white",explanation:"White defends e4 and develops simultaneously."},{san:"a6",who:"black",explanation:"THE NAJDORF MOVE! This seemingly modest pawn move prevents Nb5, prepares b5 queenside expansion, and keeps maximum flexibility. One of the most important single moves in all of chess theory."},{san:"Be3",who:"white",explanation:"White starts the English Attack setup — the bishop goes to e3 first."},{san:"e5",who:"black",explanation:"Black stakes a claim in the center and kicks the knight from d4. This is the main Najdorf structure."},{san:"Nb3",who:"white",explanation:"The knight retreats to b3, not blocking the f-file for the upcoming pawn storm."},{san:"Be6",who:"black",explanation:"The bishop develops actively, targeting b3 and supporting d5 ideas."},{san:"f3",who:"white",explanation:"The English Attack signature move! Reinforces e4 and clears the way for the g4-h4-h5 pawn storm. A direct declaration of war."},{san:"Be7",who:"black",explanation:"Black prepares to castle into safety before White's storm arrives."},{san:"Qd2",who:"white",explanation:"Connects rooks and prepares O-O-O — the pawn storm will begin immediately after."},{san:"O-O",who:"black",explanation:"Black castles! Now the race is on. Black needs queenside play before White's g4-g5 attack breaks through."},{san:"O-O-O",who:"white",explanation:"White castles queenside — the kings go to opposite sides. The English Attack's defining moment: a direct race where the first to attack the enemy king wins."},{san:"Nbd7",who:"black",explanation:"Developing the knight towards c5, where it will support the b5 break and pressure White's position."},{san:"g4",who:"white",explanation:"THE PAWN STORM BEGINS! g4-g5 is coming to kick the Nf6 and open lines against the Black king."},{san:"b5",who:"black",explanation:"Black's counter-strike! The b-pawn charges forward — b4 will hit the Nc3, and Nc5 is coming with huge pressure. The race is on!"}]}}}
,italian:{"id": "italian", "name": "Italian Game", "color": "white", "variations": {"giuoco_pianissimo": {"name": "Giuoco Pianissimo", "intro": "The Italian Game is one of the oldest openings in chess, dating back centuries. The Giuoco Pianissimo (\"very quiet game\") is its slow, strategic main line — instead of grabbing material or forcing tactics early, White builds a harmonious position, restrains Black's center, and looks to outplay the opponent in a rich middlegame. It's a fantastic opening for learning piece coordination and long-term planning.", "moves": [{"san": "e4", "who": "white", "explanation": "Classical central control — opens lines for the bishop and queen and claims the center immediately."}, {"san": "e5", "who": "black", "explanation": "Black meets in the center symmetrically. The most natural, principled reply."}, {"san": "Nf3", "who": "white", "explanation": "Develops with tempo, attacking e5 and preparing quick castling."}, {"san": "Nc6", "who": "black", "explanation": "Defends e5 and develops a piece — completely standard."}, {"san": "Bc4", "who": "white", "explanation": "The signature Italian move! The bishop eyes the vulnerable f7 square along the a2–g7 diagonal — historically chess's weakest point for Black, since it's only defended by the king.", "arrow": {"from": "c4", "to": "f7"}, "highlightSquares": ["f7"]}, {"san": "Bc5", "who": "black", "explanation": "Black mirrors White's idea, aiming the bishop at f2 — the symmetric weak point in White's camp."}, {"san": "c3", "who": "white", "explanation": "A key Italian move. This prepares d4 (a full pawn center) while giving the bishop on c4 a retreat square on c2 if it's ever attacked."}, {"san": "Nf6", "who": "black", "explanation": "Develops and attacks e4, forcing White to be precise."}, {"san": "d3", "who": "white", "explanation": "The quiet, modern approach (the Giuoco Pianissimo). Rather than rushing d4 immediately, White supports e4 first and keeps the position flexible, avoiding some sharp tactical lines that arise after an immediate d4."}, {"san": "d6", "who": "black", "explanation": "Black matches White's setup — solid, flexible, preparing quick development and castling."}, {"san": "O-O", "who": "white", "explanation": "Castling into safety — always a top priority once development allows it."}, {"san": "O-O", "who": "black", "explanation": "Black castles too. Both kings are now tucked away and the position is set for a strategic middlegame battle."}, {"san": "Re1", "who": "white", "explanation": "A useful improving move. The rook eyes the e-file and supports a future d4 break before White commits further."}, {"san": "a6", "who": "black", "explanation": "A standard prophylactic move, taking the b5 square away from White's pieces and preparing a future ...b5 expansion."}, {"san": "Nbd2", "who": "white", "explanation": "Developing the last minor piece toward the center. From d2 this knight often reroutes via f1 to g3, eyeing f5 — a classic Italian Game maneuver.", "arrow": {"from": "d2", "to": "f1"}}, {"san": "Ba7", "who": "black", "explanation": "A typical retreat — tucking the bishop safely onto the a7–g1 diagonal (the 'Italian retreat') where it stays powerful but avoids being hit by a future d4-d5 tempo gain."}, {"san": "h3", "who": "white", "explanation": "Prevents ...Ng4 or ...Bg4 ideas from harassing pieces, and gives the king a little luft (escape square) — a very typical prophylactic move in these structures."}, {"san": "h6", "who": "black", "explanation": "Black plays the same idea in reverse, ruling out Ng5 or Bg5 ideas."}, {"san": "Nf1", "who": "white", "explanation": "The point of Nbd2! The knight continues its journey toward g3, where it will eye the f5 and h5 squares and support kingside expansion.", "arrow": {"from": "d2", "to": "g3"}}, {"san": "Re8", "who": "black", "explanation": "Black centralizes the rook, mirroring White's earlier idea and preparing central play or a future ...d5 break."}, {"san": "Ng3", "who": "white", "explanation": "The knight completes its maneuver. From g3 it supports a future Nf5 jump — a very annoying outpost near Black's king — and adds pressure toward the kingside.", "arrow": {"from": "f1", "to": "g3"}}, {"san": "Be6", "who": "black", "explanation": "Black develops the last minor piece and directly challenges White's strong bishop on c4, offering a trade that would relieve some of the pressure on Black's kingside."}, {"san": "Bxe6", "who": "white", "explanation": "White accepts the trade. Keeping the bishop wasn't necessary here — after the recapture, White gains something more valuable: a lead in central space and open lines."}, {"san": "fxe6", "who": "black", "explanation": "Black recaptures toward the center. This is a real trade-off: Black's kingside pawns are now doubled (e6 and e5... actually e6 sits behind the e5 pawn), but in exchange Black gets the half-open f-file for the rook and extra central control — a very typical structural trade-off in the Italian Game. From here, the middlegame plans diverge clearly: White typically expands with d4, aims pieces at the center and queenside, and looks to exploit Black's slightly weakened king position, while Black uses the open f-file for rook activity, plays for ...d5 breaks, and keeps pieces flexible to answer White's central pressure. Both sides have chances — this is a rich, well-balanced middlegame that rewards good piece coordination over memorized theory."}]}}},ruy_lopez:{"id": "ruy_lopez", "name": "Ruy Lopez", "color": "white", "variations": {"closed_chigorin": {"name": "Closed Defense (Chigorin Variation)", "intro": "The Ruy Lopez (Spanish Game) is the most respected and deeply analyzed e4 opening in chess history, favored by nearly every World Champion. Instead of an immediate tactical fight, White applies quiet, long-term pressure on Black's e5 pawn and center. The Closed Defense, Chigorin Variation, is one of its great classical main lines — a rich strategic battleground where both sides maneuver for years-long space and structural advantages.", "moves": [{"san": "e4", "who": "white", "explanation": "Central control, opening lines for the bishop and queen."}, {"san": "e5", "who": "black", "explanation": "The symmetric, principled reply."}, {"san": "Nf3", "who": "white", "explanation": "Develops and attacks e5."}, {"san": "Nc6", "who": "black", "explanation": "Defends e5 and develops."}, {"san": "Bb5", "who": "white", "explanation": "The Ruy Lopez! The bishop pins the Nc6, indirectly pressuring e5 (since after a trade, dxc6-style ideas would still be a factor if the knight is undefended).", "arrow": {"from": "b5", "to": "c6"}, "highlightSquares": ["c6"]}, {"san": "a6", "who": "black", "explanation": "The Morphy Defense — immediately questioning the bishop and gaining a useful tempo."}, {"san": "Ba4", "who": "white", "explanation": "White keeps the pin rather than trading, maintaining pressure on the long diagonal toward c6/e5."}, {"san": "Nf6", "who": "black", "explanation": "Develops with tempo, attacking e4 and forcing White to react."}, {"san": "O-O", "who": "white", "explanation": "Rather than defending e4 directly, White castles — the e4 pawn is a well-known 'poisoned' target here since ...Nxe4 runs into tactics that favor White."}, {"san": "Be7", "who": "black", "explanation": "Prepares to castle and unpins the knight, a solid, flexible developing move."}, {"san": "Re1", "who": "white", "explanation": "Adds extra protection to e4 and prepares central expansion with d4 later — a standard prophylactic improving move."}, {"san": "b5", "who": "black", "explanation": "Gains a tempo on the bishop while grabbing queenside space — a key idea of the Morphy Defense structure."}, {"san": "Bb3", "who": "white", "explanation": "Retreats to a strong diagonal, still eyeing f7 for the rest of the game and staying flexible for future central play."}, {"san": "d6", "who": "black", "explanation": "Solidifies the e5 pawn and opens the path for Black's light-squared bishop to develop."}, {"san": "c3", "who": "white", "explanation": "Prepares the central break d4 and gives the bishop a retreat square on c2 if it's ever challenged by ...Na5 or ...Nb4."}, {"san": "O-O", "who": "black", "explanation": "Black completes development and tucks the king away safely."}, {"san": "h3", "who": "white", "explanation": "A crucial prophylactic move, ruling out ...Bg4 or ...Ng4 ideas before White commits to the center."}, {"san": "Na5", "who": "black", "explanation": "The Chigorin Variation's signature move! Black kicks the bishop and prepares ...c5, gaining serious queenside space — even though the knight looks awkward on the rim for a while."}, {"san": "Bc2", "who": "white", "explanation": "Retreats, keeping the bishop safe on a great diagonal that can support a future Qd3/Qe2 battery aimed at h7."}, {"san": "c5", "who": "black", "explanation": "Grabs central and queenside space — the point of ...Na5, since the knight no longer blocks this pawn's path."}, {"san": "d4", "who": "white", "explanation": "The thematic central break, striking at the heart of Black's structure and fighting for the initiative."}, {"san": "Qc7", "who": "black", "explanation": "A flexible, standard developing move — supports c5, connects the rooks, and keeps options open in the center."}, {"san": "Nbd2", "who": "white", "explanation": "Develops the last minor piece toward the center. This knight typically continues its journey via f1 to g3, aiming at kingside expansion with f4 later.", "arrow": {"from": "d2", "to": "f1"}}, {"san": "Nc6", "who": "black", "explanation": "The a5-knight regroups back toward the center now that it has achieved its goal of provoking ...c5 — a classic maneuvering idea in these Closed Ruy Lopez structures."}, {"san": "d5", "who": "white", "explanation": "White closes the center, gaining a long-term space advantage and setting the stage for a maneuvering battle rather than immediate tactics."}, {"san": "Nd8", "who": "black", "explanation": "Rerouting once again — typical of the Ruy Lopez's slow, maneuvering character. The knight heads toward e8-f6 or b7-d7 to find a better long-term post. From here, the middlegame plans are classic Spanish Game strategy: White expands on the kingside with Nf1-g3, f4, and sometimes g4, using the extra space from d4-d5 to attack; Black counters on the queenside with ...a5, ...Nb7-c5 or ...f5 breaks, aiming to undermine White's center. This is one of the richest, most instructive structures in all of chess — patience and piece maneuvering matter far more than memorized tactics."}]}}},queens_gambit:{"id": "queens_gambit", "name": "Queen's Gambit", "color": "white", "variations": {"declined_classical": {"name": "Queen's Gambit Declined, Classical", "intro": "The Queen's Gambit is one of the oldest and most respected openings in chess - it is not a real gambit at all, since the c4 pawn cannot safely be held by Black long-term. Instead, White offers it to lure Black's center pawn away and gain a freer, more active game. The Declined main line leads to rich, strategic middlegames built around classic minority attacks and central pawn breaks.", "moves": [{"san": "d4", "who": "white", "explanation": "Central control, opening the position for the queen and dark-squared bishop."}, {"san": "d5", "who": "black", "explanation": "The classical, symmetric reply, matching White's central claim."}, {"san": "c4", "who": "white", "explanation": "The Queen's Gambit. White offers the c-pawn as bait - if Black takes it, White gets fast development and a strong center in return, since holding the pawn with an early b5 overextends Black's position.", "arrow": {"from": "c4", "to": "d5"}}, {"san": "e6", "who": "black", "explanation": "The Queen's Gambit Declined. Black keeps the center pawn on d5 and opens the path for the dark-squared bishop, choosing solidity over material."}, {"san": "Nc3", "who": "white", "explanation": "Develops naturally, adding pressure on d5 and preparing further central play."}, {"san": "Nf6", "who": "black", "explanation": "Develops and defends d5 a second time."}, {"san": "Bg5", "who": "white", "explanation": "Pins the knight, a very standard and thematic move that keeps Black's kingside development a little awkward.", "arrow": {"from": "g5", "to": "f6"}}, {"san": "Be7", "who": "black", "explanation": "Breaks the pin and prepares to castle, the most solid, classical response."}, {"san": "e3", "who": "white", "explanation": "A quiet, flexible developing move, opening the path for the light-squared bishop and preparing Bd3 or Bxf6 ideas later."}, {"san": "O-O", "who": "black", "explanation": "Castles into safety."}, {"san": "Nf3", "who": "white", "explanation": "Develops the last knight, adding more central control before committing the king."}, {"san": "h6", "who": "black", "explanation": "A useful prophylactic move, asking the bishop on g5 to make a decision: retreat, trade on f6, or step aside to h4."}, {"san": "Bh4", "who": "white", "explanation": "Keeps the pin alive rather than releasing the tension immediately."}, {"san": "b6", "who": "black", "explanation": "A modern, flexible plan, preparing to fianchetto the light-squared bishop to b7, adding pressure on the long diagonal and on e4."}, {"san": "Rc1", "who": "white", "explanation": "A classic, quiet improving move, placing the rook on the half-open c-file where White's central pawn break will soon open lines."}, {"san": "Bb7", "who": "black", "explanation": "Completes the fianchetto, eyeing e4 and adding flexibility to Black's position."}, {"san": "cxd5", "who": "white", "explanation": "White resolves the central tension. This trade begins the classic minority attack plan - White will look to expand on the queenside with a4-a5 or b4-b5 to create weaknesses in Black's pawn structure.", "arrow": {"from": "c4", "to": "d5"}}, {"san": "exd5", "who": "black", "explanation": "Black recaptures toward the center, keeping a solid pawn structure but accepting a d5 pawn that could become a long-term target."}, {"san": "Bd3", "who": "white", "explanation": "Develops the last minor piece to an active diagonal, eyeing a future kingside attack and supporting central operations."}, {"san": "Nbd7", "who": "black", "explanation": "Completes development, preparing a future c5 break or Re8, and keeping the position flexible. From here, White typically pursues the minority attack on the queenside with b4-b5, while Black looks for central or kingside counterplay with c5 or Ne4 - a rich, well-studied middlegame structure that rewards patient maneuvering over sharp tactics."}]}}},caro_kann:{"id": "caro_kann", "name": "Caro-Kann Defense", "color": "black", "variations": {"classical": {"name": "Classical Variation", "intro": "The Caro-Kann is one of the most solid and respected defenses to 1.e4, favored by World Champions like Karpov and Capablanca. Unlike the French Defense, Black's light-squared bishop gets developed before the pawn chain locks it in - a key structural advantage. The Classical Variation is the main line, leading to rich strategic play where Black often ends up in a slightly worse but very resilient position.", "moves": [{"san": "e4", "who": "white", "explanation": "Central control, claiming space and opening lines."}, {"san": "c6", "who": "black", "explanation": "The Caro-Kann. Black prepares d5 to challenge the center immediately, while keeping the option to develop the light-squared bishop outside the pawn chain - the defense's key structural idea."}, {"san": "d4", "who": "white", "explanation": "White takes full central control, the natural follow-up."}, {"san": "d5", "who": "black", "explanation": "Striking back in the center - this pawn is well-supported by the c6 pawn."}, {"san": "Nc3", "who": "white", "explanation": "Develops and defends e4, keeping the central tension."}, {"san": "dxe4", "who": "black", "explanation": "Black resolves the tension. This is the main line - Black is happy to simplify here since the resulting structure favors solid, resilient play."}, {"san": "Nxe4", "who": "white", "explanation": "Recaptures, centralizing the knight with tempo-gaining potential against Black's next moves."}, {"san": "Bf5", "who": "black", "explanation": "The point of the Caro-Kann. Black develops the light-squared bishop actively before playing e6, avoiding the classic problem the French Defense has of trapping this piece behind its own pawn chain.", "arrow": {"from": "c8", "to": "f5"}}, {"san": "Ng3", "who": "white", "explanation": "Attacks the bishop, gaining a tempo and continuing development."}, {"san": "Bg6", "who": "black", "explanation": "Retreats to a safe, active square, still eyeing the long diagonal and staying out of tactical trouble."}, {"san": "h4", "who": "white", "explanation": "An aggressive, thematic try, gaining space on the kingside and threatening h5 to harass the bishop further."}, {"san": "h6", "who": "black", "explanation": "Prevents h5, a necessary precaution to keep the bishop's retreat squares intact."}, {"san": "Nf3", "who": "white", "explanation": "Develops naturally, adding central control and preparing quick development."}, {"san": "Nd7", "who": "black", "explanation": "Develops flexibly, preparing a knight to f6 next and keeping options open for where the king will go."}, {"san": "Bd3", "who": "white", "explanation": "Offers a trade of the light-squared bishops. Even though Black's bishop worked hard to get to a good square, trading it off here is fine for White - it simplifies the position while keeping a small structural edge.", "arrow": {"from": "f1", "to": "d3"}}, {"san": "Bxd3", "who": "black", "explanation": "Black accepts the trade rather than retreating again, simplifying the position and removing White's well-placed bishop."}, {"san": "Qxd3", "who": "white", "explanation": "Recaptures with the queen, keeping pressure on the center and eyeing a future attack after castling long."}, {"san": "Qc7", "who": "black", "explanation": "A flexible, standard developing move, preparing to castle queenside and keeping the queen actively placed."}, {"san": "Bd2", "who": "white", "explanation": "Develops the last minor piece and prepares long castling, aiming for an aggressive plan with opposite-side castling and a pawn storm."}, {"san": "O-O-O", "who": "black", "explanation": "Black castles queenside too, matching White's plan. From here the game typically becomes a race: both sides castle on opposite wings and push pawns toward the enemy king - a sharp, well-studied structure where Black's solid structure and safely developed bishop give real chances to hold the balance or seize the initiative."}]}, "exchange": {"name": "Exchange Variation", "intro": "The Exchange Variation is a quieter try against the Caro-Kann. Rather than fighting for extra central space, White trades pawns immediately, aiming for a small, lasting edge based on piece activity and a slight structural plus rather than a direct attack. It's a great line for players who prefer calm, strategic games over sharp tactics.", "moves": [{"san": "e4", "who": "white", "explanation": "Central control, claiming space."}, {"san": "c6", "who": "black", "explanation": "The Caro-Kann, preparing d5 while keeping the light-squared bishop's development flexible."}, {"san": "d4", "who": "white", "explanation": "Full central control."}, {"san": "d5", "who": "black", "explanation": "Challenging the center directly."}, {"san": "exd5", "who": "white", "explanation": "The Exchange Variation. Rather than fighting for the center with Nc3, White simplifies immediately - a quieter approach that still offers chances based on piece activity and structure.", "arrow": {"from": "e4", "to": "d5"}}, {"san": "cxd5", "who": "black", "explanation": "Black recaptures, resulting in a symmetrical pawn structure. The position is simple on the surface, but both sides need to play accurately to make the most of small structural nuances."}, {"san": "Bd3", "who": "white", "explanation": "Develops actively, eyeing a future attack on the kingside and controlling the important e4 and h7 squares."}, {"san": "Nc6", "who": "black", "explanation": "Develops naturally, adding pressure on d4."}, {"san": "c3", "who": "white", "explanation": "Solidifies the center and supports a future b4-b5 queenside expansion while keeping d4 firmly defended."}, {"san": "Nf6", "who": "black", "explanation": "Develops, preparing to castle."}, {"san": "Bf4", "who": "white", "explanation": "Develops the bishop actively before it gets blocked in by a future e3, and eyes a future Ne5 or Qb3 idea."}, {"san": "Bg4", "who": "black", "explanation": "Pins the knight on f3, adding pressure and preparing to trade off a piece that could otherwise become annoying."}, {"san": "Nbd2", "who": "white", "explanation": "Develops the last knight, preparing to castle and adding support to the center."}, {"san": "e6", "who": "black", "explanation": "A solid, flexible move, preparing to develop the dark-squared bishop and get the king to safety."}, {"san": "Qb3", "who": "white", "explanation": "A thematic idea in this structure, eyeing the b7 pawn and adding pressure that Black must account for.", "arrow": {"from": "d1", "to": "b3"}, "highlightSquares": ["b7"]}, {"san": "Qd7", "who": "black", "explanation": "A solid, standard defensive response, protecting b7 indirectly and keeping development on track."}, {"san": "Rd1", "who": "white", "explanation": "A quiet, solid improving move, adding the rook to the d-file where the central tension will eventually matter, ahead of castling."}, {"san": "Bd6", "who": "black", "explanation": "Develops the last minor piece to an active square, preparing to castle and adding a defender to key central squares."}, {"san": "O-O", "who": "white", "explanation": "Castles into safety. From here the position is balanced and strategic: both sides maneuver pieces and look for chances to create weaknesses in the symmetrical pawn structure. Games in this line are typically decided by who handles the resulting middlegame more precisely, rather than by memorized theory."}]}}},bird:{"id": "bird", "name": "Bird Opening", "color": "white", "variations": {"main": {"name": "Main Line", "intro": "The Bird Opening is an unusual but perfectly sound choice for White, staking a claim on e5 from the flank rather than fighting for the center directly. It often transposes into structures similar to a reversed Dutch Defense, but with an extra tempo since White moves first - a great pick for players who want to sidestep heavily analyzed main lines.", "moves": [{"san": "f4", "who": "white", "explanation": "The Bird Opening! An unusual but sound choice - White stakes a claim on e5 from the flank rather than the center, aiming for a setup similar to a reversed Dutch Defense with an extra tempo."}, {"san": "d5", "who": "black", "explanation": "A natural, solid reply, matching White's flank approach with central occupation."}, {"san": "Nf3", "who": "white", "explanation": "Develops naturally, preparing to control e5 and castle quickly."}, {"san": "Nf6", "who": "black", "explanation": "Develops symmetrically, adding pressure toward the center."}, {"san": "e3", "who": "white", "explanation": "A quiet, flexible move, opening the path for the light-squared bishop and preparing to develop smoothly."}, {"san": "g6", "who": "black", "explanation": "Black chooses a fianchetto setup, aiming pressure at the long diagonal and preparing quick, safe development."}, {"san": "Be2", "who": "white", "explanation": "A modest but solid developing move, preparing to castle without committing to a specific plan too early."}, {"san": "Bg7", "who": "black", "explanation": "Completes the fianchetto, eyeing the long diagonal and the center."}, {"san": "O-O", "who": "white", "explanation": "Castles into safety, a top priority once development allows."}, {"san": "O-O", "who": "black", "explanation": "Black castles too, both kings now tucked away."}, {"san": "d3", "who": "white", "explanation": "Solidifies the center and keeps the position flexible, preparing to expand with either c4 or Ne5 ideas next."}, {"san": "c5", "who": "black", "explanation": "Gains queenside space and prepares to develop the queenside pieces actively."}, {"san": "Qe1", "who": "white", "explanation": "A thematic Bird Opening idea! The queen prepares to swing to h4 or g3, supporting a future kingside attack alongside the f4 pawn.", "arrow": {"from": "d1", "to": "e1"}}, {"san": "Nc6", "who": "black", "explanation": "Develops naturally, adding pressure on d4 and preparing central or queenside expansion."}, {"san": "Qh4", "who": "white", "explanation": "Completes the maneuver, directly eyeing the kingside and supporting an eventual e4 or g4 pawn storm.", "arrow": {"from": "e1", "to": "h4"}}, {"san": "Re8", "who": "black", "explanation": "A useful improving move, preparing central breaks and adding support along the e-file. From here, the game becomes a strategic race: White looks to expand on the kingside with e4 or g4 supported by the queen on h4, while Black counters in the center or on the queenside with b5 and c4 breaks. The Bird Opening rewards players who enjoy flank-based, imbalanced strategic battles."}]}}},dutch:{"id": "dutch", "name": "Dutch Defense", "color": "black", "variations": {"leningrad": {"name": "Leningrad Variation", "intro": "The Dutch Defense stakes a claim on e4 from the flank with an early f5, aiming for dynamic, unbalanced play rather than a symmetric center. The Leningrad Variation is its sharpest form - Black fianchettoes both bishops, building an aggressive setup aimed squarely at White's king.", "moves": [{"san": "d4", "who": "white", "explanation": "Central control, the standard start for many closed openings."}, {"san": "f5", "who": "black", "explanation": "The Dutch Defense! Black stakes a claim on e4 from the flank, aiming for an aggressive, unbalanced game rather than a symmetric center fight."}, {"san": "g3", "who": "white", "explanation": "A flexible, modern approach - White prepares to fianchetto and meet Black's kingside expansion with solid, patient development."}, {"san": "Nf6", "who": "black", "explanation": "Develops naturally, adding control over e4 and central squares."}, {"san": "Bg2", "who": "white", "explanation": "Completes the fianchetto, aiming at the long diagonal and eventually the queenside."}, {"san": "g6", "who": "black", "explanation": "The Leningrad Variation's key move! Black also fianchettoes the dark-squared bishop, aiming for a hyper-aggressive setup with pieces aimed at the kingside - a much sharper approach than the older Classical or Stonewall systems.", "arrow": {"from": "f8", "to": "g7"}}, {"san": "Nf3", "who": "white", "explanation": "Develops naturally, preparing to castle and adding control over the center."}, {"san": "Bg7", "who": "black", "explanation": "Completes the fianchetto, eyeing the long diagonal toward White's queenside."}, {"san": "O-O", "who": "white", "explanation": "Castles into safety."}, {"san": "O-O", "who": "black", "explanation": "Black castles too, completing kingside development."}, {"san": "c4", "who": "white", "explanation": "Gains central and queenside space, a standard plan in these fianchetto structures."}, {"san": "d6", "who": "black", "explanation": "Solidifies the center and opens the path for the light-squared bishop's development."}, {"san": "Nc3", "who": "white", "explanation": "Develops naturally, adding pressure on the center and preparing further expansion."}, {"san": "Qe8", "who": "black", "explanation": "A key Leningrad Dutch idea! The queen prepares to swing to h5 or g6, joining the kingside attack alongside the f5 pawn and the fianchettoed bishop.", "arrow": {"from": "d8", "to": "e8"}}, {"san": "d5", "who": "white", "explanation": "Gains space in the center, restricting Black's own central breaks and fixing the structure."}, {"san": "Na6", "who": "black", "explanation": "Develops flexibly, preparing to reroute the knight to c5 where it will be very well placed, eyeing e4 and supporting queenside or central play. From here, the game is a real strategic battle: Black's pieces are aimed menacingly at the White king, and if White is not careful, moves like f4-f3 or Qh5 can generate a real attack. Meanwhile White looks to use the extra central space and target Black's slightly weakened kingside light squares in return."}]}, "classical": {"name": "Classical Variation", "intro": "The Classical Dutch takes a more restrained approach than the Leningrad - Black develops solidly with e6 and Be7 rather than fianchettoing both bishops, aiming for a flexible, positionally sound game while keeping the option of a kingside initiative later with a queen maneuver to h5 or g6.", "moves": [{"san": "d4", "who": "white", "explanation": "Central control."}, {"san": "f5", "who": "black", "explanation": "The Dutch Defense, staking a claim on e4 and aiming for dynamic, aggressive play."}, {"san": "g3", "who": "white", "explanation": "The modern fianchetto approach, meeting Black's flank expansion with solid, flexible development."}, {"san": "Nf6", "who": "black", "explanation": "Develops, adding control over e4."}, {"san": "Bg2", "who": "white", "explanation": "Completes the fianchetto."}, {"san": "e6", "who": "black", "explanation": "The Classical Variation. Rather than fianchettoing the dark-squared bishop like in the Leningrad, Black keeps things solid, preparing to develop with Be7 and O-O in a more restrained, positional style."}, {"san": "Nf3", "who": "white", "explanation": "Develops naturally, preparing to castle."}, {"san": "Be7", "who": "black", "explanation": "A solid, flexible developing move, preparing to castle quickly."}, {"san": "O-O", "who": "white", "explanation": "Castles into safety."}, {"san": "O-O", "who": "black", "explanation": "Black castles too."}, {"san": "c4", "who": "white", "explanation": "Gains central and queenside space, the standard plan against Dutch setups."}, {"san": "d6", "who": "black", "explanation": "Solidifies the center, opening the path for the light-squared bishop and supporting e5 ideas later."}, {"san": "Nc3", "who": "white", "explanation": "Develops naturally, adding pressure on the center."}, {"san": "Qe8", "who": "black", "explanation": "A very typical Classical Dutch idea - the queen prepares to reroute to h5 or g6 to support a kingside initiative, similar in spirit to the Leningrad but from a more solid structural base."}, {"san": "Re1", "who": "white", "explanation": "A useful improving move, preparing a future e4 central break and adding support to the center."}, {"san": "Qg6", "who": "black", "explanation": "Completes the maneuver, adding real pressure toward the kingside and eyeing the g-file and long diagonal ideas alongside future piece regrouping.", "arrow": {"from": "e8", "to": "g6"}}, {"san": "e4", "who": "white", "explanation": "The thematic central break! White strikes back in the center now that development is complete, challenging Black's f5 pawn and fighting for the initiative. From here, sharp, well-studied lines follow where both central tension and kingside play are the main themes - a rich battleground that rewards accurate calculation on both sides."}]}, "stonewall": {"name": "Stonewall Variation", "intro": "The Stonewall Dutch is built around a rigid pawn chain on d5-e6-f5. This gives Black a permanent grip on e4 at the cost of the e5 square and some piece mobility - a classic trade-off. It's an excellent choice for players who enjoy clear plans and direct kingside attacking chances.", "moves": [{"san": "d4", "who": "white", "explanation": "Central control."}, {"san": "f5", "who": "black", "explanation": "The Dutch Defense."}, {"san": "g3", "who": "white", "explanation": "The flexible fianchetto approach."}, {"san": "Nf6", "who": "black", "explanation": "Develops, controlling e4."}, {"san": "Bg2", "who": "white", "explanation": "Completes the fianchetto."}, {"san": "e6", "who": "black", "explanation": "Prepares a solid, restrained setup."}, {"san": "Nf3", "who": "white", "explanation": "Develops naturally."}, {"san": "d5", "who": "black", "explanation": "The Stonewall Variation's signature move! Black builds a rigid pawn chain on d5-e6-f5, taking firm control of e4 at the cost of some flexibility - especially the permanently weakened e5 square. This trade-off defines the whole variation.", "arrow": {"from": "d5", "to": "e6"}}, {"san": "O-O", "who": "white", "explanation": "Castles into safety."}, {"san": "Bd6", "who": "black", "explanation": "Develops the dark-squared bishop actively, aiming at the kingside and supporting a future attack alongside the f5 pawn."}, {"san": "c4", "who": "white", "explanation": "Challenges Black's center and gains queenside space, a standard try against the Stonewall structure."}, {"san": "c6", "who": "black", "explanation": "Solidifies the center, keeping the Stonewall chain intact and preparing to complete development."}, {"san": "Nc3", "who": "white", "explanation": "Develops naturally, adding pressure and preparing central or queenside operations."}, {"san": "O-O", "who": "black", "explanation": "Castles into safety, completing kingside development."}, {"san": "Bf4", "who": "white", "explanation": "Offers a trade of dark-squared bishops, aiming to reduce Black's attacking potential by removing this key attacking piece.", "arrow": {"from": "c1", "to": "f4"}}, {"san": "Bxf4", "who": "black", "explanation": "Black accepts the trade rather than retreating, since keeping the bishop on the board is not essential to the Stonewall's core plans."}, {"san": "gxf4", "who": "white", "explanation": "Recaptures. This slightly damages White's kingside pawn structure but opens the g-file for a rook and adds central control. From here, Black typically pursues a kingside attack with moves like Ne4, Qf6, and eventually a rook lift to h5 or g5, using the rigid but powerful Stonewall structure as a launchpad, while White looks to exploit the permanent weakness on e5 with a well-timed knight maneuver."}]}}},kings_gambit:{"id": "kings_gambit", "name": "King's Gambit", "color": "white", "variations": {"accepted": {"name": "King's Gambit Accepted", "intro": "The King's Gambit is one of the oldest and most romantic openings in chess history, played by legends from Morphy to Fischer. White offers a pawn immediately to open lines and accelerate development, aiming for a direct, all-out attack on Black's king rather than a slow positional game.", "moves": [{"san": "e4", "who": "white", "explanation": "Central control, opening lines immediately."}, {"san": "e5", "who": "black", "explanation": "The symmetric, classical reply."}, {"san": "f4", "who": "white", "explanation": "The King's Gambit! One of the oldest and most romantic openings in chess. White offers a pawn to open the f-file and the a2-g8 diagonal, aiming for fast development and a direct attack on Black's king.", "arrow": {"from": "f2", "to": "f4"}}, {"san": "exf4", "who": "black", "explanation": "The King's Gambit Accepted. Black grabs the pawn, the most principled and testing response."}, {"san": "Nf3", "who": "white", "explanation": "Prevents Qh4+ (which would win a tempo by forcing White's king to move) and prepares to recapture the f4 pawn or continue developing with tempo."}, {"san": "g5", "who": "black", "explanation": "A sharp, classical try to hold onto the extra pawn, defending f4 and preparing g4 to harass the knight."}, {"san": "h4", "who": "white", "explanation": "A thematic, aggressive response, immediately challenging Black's kingside pawns before they can consolidate.", "arrow": {"from": "h2", "to": "h4"}}, {"san": "g4", "who": "black", "explanation": "Black pushes forward, attacking the knight and trying to hold everything together."}, {"san": "Ne5", "who": "white", "explanation": "The critical main line! The knight jumps to a very active central square, eyeing f7 and staying safe from the pawn storm.", "arrow": {"from": "f3", "to": "e5"}}, {"san": "Nf6", "who": "black", "explanation": "Develops naturally, adding control over e4 and preparing to challenge White's active knight."}, {"san": "Bc4", "who": "white", "explanation": "Develops actively, adding a second attacker toward f7 - a classic King's Gambit attacking idea.", "arrow": {"from": "c4", "to": "f7"}}, {"san": "d5", "who": "black", "explanation": "Strikes back in the center, offering a pawn to gain time and open lines for Black's own pieces."}, {"san": "exd5", "who": "white", "explanation": "Accepts, keeping the material advantage and the initiative."}, {"san": "Bd6", "who": "black", "explanation": "Develops actively, preparing to castle and adding pressure toward White's kingside, where the king has not yet found safety. From here, the position is extremely sharp and double-edged - both kings are exposed, tactics are everywhere, and precise calculation matters far more than general principles. This is the King's Gambit's enduring appeal: a wild, attacking battle from the very first moves."}]}}},vienna:{"id": "vienna", "name": "Vienna Game", "color": "white", "variations": {"main": {"name": "Main Line", "intro": "The Vienna Game develops the queenside knight before committing to a central pawn structure, keeping options flexible - White can steer toward a sharp f4 gambit or, as in this modern main line, a quieter fianchetto setup with rich strategic potential.", "moves": [{"san": "e4", "who": "white", "explanation": "Central control."}, {"san": "e5", "who": "black", "explanation": "The classical, symmetric reply."}, {"san": "Nc3", "who": "white", "explanation": "The Vienna Game! A flexible move order - White develops naturally while keeping options open for either a quiet positional game or a sharp f4 gambit line later.", "arrow": {"from": "b1", "to": "c3"}}, {"san": "Nf6", "who": "black", "explanation": "Develops and attacks e4, the most natural, testing response."}, {"san": "g3", "who": "white", "explanation": "The modern, positional approach - White prepares to fianchetto the bishop, adding pressure to the long diagonal and keeping the position flexible rather than committing to an immediate f4 gambit."}, {"san": "Bc5", "who": "black", "explanation": "Develops actively, eyeing f2 and preparing to castle quickly."}, {"san": "Bg2", "who": "white", "explanation": "Completes the fianchetto, aiming at the center and Black's queenside."}, {"san": "d6", "who": "black", "explanation": "Solidifies the center and opens the path for the light-squared bishop's development."}, {"san": "Nge2", "who": "white", "explanation": "A flexible developing move, keeping the f-pawn free to advance later and adding support to the center.", "arrow": {"from": "g1", "to": "e2"}}, {"san": "O-O", "who": "black", "explanation": "Castles into safety, completing kingside development."}, {"san": "O-O", "who": "white", "explanation": "Castles into safety too."}, {"san": "Nc6", "who": "black", "explanation": "Completes development, adding pressure on d4 and e5, and preparing further central or queenside play."}, {"san": "d3", "who": "white", "explanation": "A solid, flexible move, keeping the center firm and preparing to complete development smoothly."}, {"san": "a6", "who": "black", "explanation": "A useful prophylactic move, preparing a future b5 expansion and taking the b5 square away from White's minor pieces."}, {"san": "Nd5", "who": "white", "explanation": "A thematic central outpost, offering a trade of pieces and adding pressure on Black's position. From here, the game becomes a rich positional battle: both sides maneuver for small advantages, with White's flexible piece placement from the fianchetto giving good long-term chances, while Black looks for active piece play and central or queenside breaks to generate counterplay."}]}}},king_indian:{"id": "king_indian", "name": "King's Indian Defense", "color": "black", "variations": {"classical": {"name": "Classical Variation", "intro": "The King's Indian Defense is one of the most fighting, ambitious defenses in chess. Black allows White to build a big classical center, planning to strike back at it later with pieces and pawn breaks. The resulting games are famous for opposite-wing pawn storms and sharp strategic races.", "moves": [{"san": "d4", "who": "white", "explanation": "Central control, the standard start for many closed openings."}, {"san": "Nf6", "who": "black", "explanation": "The King's Indian Defense begins! Black allows White to build a big center, planning to strike back at it later with pieces and pawn breaks rather than contest it immediately."}, {"san": "c4", "who": "white", "explanation": "Gains additional central space, a natural follow-up."}, {"san": "g6", "who": "black", "explanation": "Prepares the King's Indian's signature fianchetto, aiming the bishop down the long diagonal at White's center.", "arrow": {"from": "f8", "to": "g7"}}, {"san": "Nc3", "who": "white", "explanation": "Develops naturally, adding control over the center."}, {"san": "Bg7", "who": "black", "explanation": "Completes the fianchetto, a hallmark of the King's Indian setup."}, {"san": "e4", "who": "white", "explanation": "White builds the full 'Classical' big center - exactly what Black invited. This is the critical main line test of the whole opening."}, {"san": "d6", "who": "black", "explanation": "Solidifies Black's own position and opens the path for the dark-squared bishop's diagonal to stay open, while preparing to castle."}, {"san": "Nf3", "who": "white", "explanation": "Develops naturally, preparing to castle and adding support to the center."}, {"san": "O-O", "who": "black", "explanation": "Castles into safety, completing kingside development."}, {"san": "Be2", "who": "white", "explanation": "A flexible, solid developing move, preparing to castle."}, {"san": "e5", "who": "black", "explanation": "The thematic King's Indian central break! Black strikes at White's big center directly, fighting for central space and opening lines for pieces.", "arrow": {"from": "e7", "to": "e5"}, "highlightSquares": ["d4"]}, {"san": "O-O", "who": "white", "explanation": "Castles into safety."}, {"san": "Nc6", "who": "black", "explanation": "Develops naturally, adding pressure on d4 and preparing further central operations."}, {"san": "d5", "who": "white", "explanation": "Closes the center, gaining a long-term space advantage - a critical strategic decision that defines the rest of the game."}, {"san": "Ne7", "who": "black", "explanation": "Rerouting the knight, since c6 no longer has a great future there - a very typical King's Indian maneuver, heading toward g6 or f5 to support a future kingside pawn storm with f5."}, {"san": "Ne1", "who": "white", "explanation": "White begins a well-known maneuvering plan, rerouting the knight toward d3 to support a future queenside expansion with c5 and b4. From here, the game becomes a classic King's Indian race: White expands on the queenside with c5 and b4, while Black launches a kingside pawn storm with f5-f4 and a direct attack on the king. This opposite-wing strategic race is one of the most famous and exciting structures in all of chess."}]}}},alapin:{"id": "alapin", "name": "Alapin Sicilian (Anti-Sicilian)", "color": "white", "variations": {"main": {"name": "Main Line", "intro": "The Alapin Variation is White's most popular way of sidestepping the sharpest main-line Sicilian theory. Instead of Nf3 and d4 immediately, White prepares c3 and d4 together, aiming to build a safe, strong classical center without allowing Black's usual sharp counterplay.", "moves": [{"san": "e4", "who": "white", "explanation": "Central control."}, {"san": "c5", "who": "black", "explanation": "The Sicilian Defense, fighting for the center asymmetrically."}, {"san": "c3", "who": "white", "explanation": "The Alapin Variation! Rather than entering the sharp main-line theory after Nf3 and d4, White prepares d4 in a way that will build a full classical center, sidestepping most of Black's sharpest Sicilian preparation.", "arrow": {"from": "c2", "to": "c3"}}, {"san": "Nf6", "who": "black", "explanation": "The most direct, testing response, attacking e4 immediately."}, {"san": "e5", "who": "white", "explanation": "Gains space and gains a tempo, pushing the knight away."}, {"san": "Nd5", "who": "black", "explanation": "Retreats to a safe, central square, ready to be challenged again."}, {"san": "d4", "who": "white", "explanation": "Builds the full classical center, exactly the point of the Alapin - White gets a strong, safe center without allowing Black's usual sharp counterplay."}, {"san": "cxd4", "who": "black", "explanation": "Captures, following standard principles of challenging the center."}, {"san": "Nf3", "who": "white", "explanation": "Develops naturally, preparing to recapture the pawn on d4 with a piece and adding pressure to the center."}, {"san": "Nc6", "who": "black", "explanation": "Develops, adding pressure on d4 and preparing further central play."}, {"san": "Bc4", "who": "white", "explanation": "Develops actively, eyeing the d5 knight and adding pressure toward f7.", "arrow": {"from": "c4", "to": "d5"}}, {"san": "Nb6", "who": "black", "explanation": "Retreats the knight to a safer square, keeping development on track while avoiding further tempo losses."}, {"san": "Bb3", "who": "white", "explanation": "Retreats to a safe, still-active diagonal, keeping long-term pressure on the queenside and center."}, {"san": "d6", "who": "black", "explanation": "Solidifies the center and prepares to complete development smoothly, a natural, flexible choice."}, {"san": "O-O", "who": "white", "explanation": "Castles into safety, completing the key developing tasks. From here, White typically enjoys a comfortable space advantage from the classical center, while Black looks for ways to challenge it with timely breaks like d5 or f5. The Alapin gives White a safe, strategically sound alternative to razor-sharp main-line Sicilian theory - ideal for players who want fighting chances without memorizing forcing lines twenty moves deep."}]}}},french:{"id": "french", "name": "French Defense", "color": "black", "variations": {"classical": {"name": "Classical Variation", "intro": "The French Defense is a rock-solid response to 1.e4, built around a firm central pawn chain. Black accepts a temporarily cramped position in exchange for a structure that's very hard to attack directly, and looks to strike back with the thematic c5 pawn break once development is complete.", "moves": [{"san": "e4", "who": "white", "explanation": "Central control, claiming space and opening lines."}, {"san": "e6", "who": "black", "explanation": "The French Defense. Black prepares d5 to challenge the center, accepting a slightly cramped position in exchange for a very solid pawn structure."}, {"san": "d4", "who": "white", "explanation": "White takes full central control."}, {"san": "d5", "who": "black", "explanation": "Striking back in the center, the point of e6 - this pawn is well-supported."}, {"san": "Nc3", "who": "white", "explanation": "Develops and defends e4, keeping the central tension alive."}, {"san": "Nf6", "who": "black", "explanation": "The Classical Variation. Black develops and attacks e4 directly, adding more pressure to the center."}, {"san": "Bg5", "who": "white", "explanation": "Pins the knight, a very standard and thematic move that keeps Black's kingside development a little awkward.", "arrow": {"from": "g5", "to": "f6"}}, {"san": "Be7", "who": "black", "explanation": "Breaks the pin and prepares to castle, the most solid, principled response."}, {"san": "e5", "who": "white", "explanation": "Gains space and gains a tempo, pushing the knight away and locking the center - a critical strategic decision that defines the whole game."}, {"san": "Nfd7", "who": "black", "explanation": "Retreats, the only reasonable square, and prepares to challenge White's space advantage with a timely c5 break."}, {"san": "Bxe7", "who": "white", "explanation": "Trades off the bishop, since it no longer has a great diagonal to work with once the center is locked."}, {"san": "Qxe7", "who": "black", "explanation": "Recaptures naturally, keeping development on track and eyeing a future c5 or f6 break."}, {"san": "f4", "who": "white", "explanation": "Solidifies the center further and prepares a kingside expansion, a typical plan once the center is locked with pawns facing each other."}, {"san": "O-O", "who": "black", "explanation": "Castles into safety, completing kingside development."}, {"san": "Nf3", "who": "white", "explanation": "Develops naturally, adding support to the center and preparing to castle."}, {"san": "c5", "who": "black", "explanation": "The thematic French break! Black strikes at the base of White's pawn chain, fighting for queenside space and counterplay - the key idea behind the whole opening.", "arrow": {"from": "c7", "to": "c5"}, "highlightSquares": ["d4"]}, {"san": "Be2", "who": "white", "explanation": "A flexible, solid developing move, preparing to castle and keeping the center intact while Black's queenside pressure builds."}, {"san": "Nc6", "who": "black", "explanation": "Develops naturally, adding pressure on d4 and completing development. From here, the game becomes a classic French Defense strategic battle: White looks to use the extra kingside space for an attack, while Black counters in the center and queenside with breaks like c5 and f6, aiming to undermine White's locked pawn chain - one of the richest strategic structures in chess."}]}}},english:{"id": "english", "name": "English Opening", "color": "white", "variations": {"reversed_sicilian": {"name": "Reversed Sicilian", "intro": "The English Opening is one of the most flexible ways to start a game. By playing on the flank with c4, White keeps options open for many different central structures, often transposing into other openings entirely. This line treats the position like a Sicilian Defense with the colors reversed and an extra tempo for White.", "moves": [{"san": "c4", "who": "white", "explanation": "The English Opening! A flexible flank opening - White claims the d5 square from the side and keeps options open for many different central structures."}, {"san": "e5", "who": "black", "explanation": "The Reversed Sicilian - Black grabs central space immediately, treating the position like a Sicilian Defense with colors reversed and an extra tempo."}, {"san": "Nc3", "who": "white", "explanation": "Develops naturally, adding control over d5 and e4."}, {"san": "Nf6", "who": "black", "explanation": "Develops, adding pressure toward the center."}, {"san": "Nf3", "who": "white", "explanation": "Develops and adds a second attacker toward e5, forcing Black to be precise."}, {"san": "Nc6", "who": "black", "explanation": "Defends e5 and develops, completely natural."}, {"san": "g3", "who": "white", "explanation": "The classic English fianchetto setup, preparing to add long-diagonal pressure and castle quickly."}, {"san": "Bb4", "who": "black", "explanation": "Pins the knight, adding pressure and preparing to potentially double White's pawns if the bishop is not challenged."}, {"san": "Bg2", "who": "white", "explanation": "Completes the fianchetto regardless, keeping the long-term plan intact."}, {"san": "O-O", "who": "black", "explanation": "Castles into safety, completing kingside development."}, {"san": "O-O", "who": "white", "explanation": "Castles into safety too."}, {"san": "e4", "who": "black", "explanation": "Gains extra central space, a natural follow-up in this structure."}, {"san": "d3", "who": "white", "explanation": "A flexible, solid move, keeping the position sound and preparing to complete development smoothly."}, {"san": "Bxc3", "who": "black", "explanation": "Trades the bishop for the knight, doubling White's pawns - a real structural concession White must deal with."}, {"san": "bxc3", "who": "white", "explanation": "Recaptures. The doubled pawns look like a weakness, but they also open the b-file for White's rook and add central support - a fair trade-off typical of this structure. From here, the game is a rich strategic battle where both sides maneuver for small advantages: White uses the open b-file and bishop pair, while Black looks to exploit the static pawn weaknesses over the long term."}]}}},nimzo_indian:{"id": "nimzo_indian", "name": "Nimzo-Indian Defense", "color": "black", "variations": {"main": {"name": "Main Line", "intro": "The Nimzo-Indian Defense is one of the most respected and deeply studied defenses in all of chess, played by nearly every World Champion. Black pins White's knight immediately, aiming to damage the pawn structure or gain the bishop pair - a purely strategic idea that leads to rich, well-understood middlegame battles.", "moves": [{"san": "d4", "who": "white", "explanation": "Central control."}, {"san": "Nf6", "who": "black", "explanation": "Develops flexibly, keeping options open for several different Indian Defense systems."}, {"san": "c4", "who": "white", "explanation": "Gains additional central space."}, {"san": "e6", "who": "black", "explanation": "Prepares the Nimzo-Indian's key move next, keeping the position flexible and solid."}, {"san": "Nc3", "who": "white", "explanation": "Develops naturally, adding control over the center."}, {"san": "Bb4", "who": "black", "explanation": "The Nimzo-Indian Defense! Black pins the knight immediately, threatening to damage White's pawn structure if the bishop is not addressed - one of the most respected defenses in all of chess.", "arrow": {"from": "b4", "to": "c3"}}, {"san": "e3", "who": "white", "explanation": "A solid, flexible response, preparing to develop the light-squared bishop and keeping the option to recapture with the pawn if the bishop trades on c3."}, {"san": "O-O", "who": "black", "explanation": "Castles into safety, completing kingside development."}, {"san": "Bd3", "who": "white", "explanation": "Develops actively, aiming at the kingside and preparing to castle."}, {"san": "d5", "who": "black", "explanation": "Strikes in the center, challenging White's space and following classical principles of central counterplay."}, {"san": "Nf3", "who": "white", "explanation": "Develops naturally, adding support to the center and preparing to castle."}, {"san": "c5", "who": "black", "explanation": "Adds more pressure on the center, a very typical Nimzo-Indian idea of attacking d4 from multiple angles."}, {"san": "O-O", "who": "white", "explanation": "Castles into safety."}, {"san": "Nc6", "who": "black", "explanation": "Develops, adding more pressure on d4 and completing development."}, {"san": "a3", "who": "white", "explanation": "A critical try, forcing Black to resolve the pin on c3 immediately rather than keep the tension."}, {"san": "Bxc3", "who": "black", "explanation": "Trades the bishop for the knight, following the main plan - damaging White's structure is worth giving up the bishop pair."}, {"san": "bxc3", "who": "white", "explanation": "Recaptures, accepting doubled pawns in exchange for the bishop pair and central control. From here, the game becomes a classic Nimzo-Indian strategic battle: Black targets White's doubled c-pawns over the long term with pieces and pawn breaks, while White uses the bishop pair and central space for active piece play - one of the deepest and most respected strategic struggles in chess."}]}}},scotch:{"id": "scotch", "name": "Scotch Game", "color": "white", "variations": {"main": {"name": "Main Line", "intro": "The Scotch Game strikes in the center immediately with an early d4, aiming to open the position and use a lead in development to generate an initiative - a sharper, more direct alternative to the slower Italian Game or Ruy Lopez.", "moves": [{"san": "e4", "who": "white", "explanation": "Central control."}, {"san": "e5", "who": "black", "explanation": "The classical, symmetric reply."}, {"san": "Nf3", "who": "white", "explanation": "Develops and attacks e5."}, {"san": "Nc6", "who": "black", "explanation": "Defends e5 and develops."}, {"san": "d4", "who": "white", "explanation": "The Scotch Game! Rather than the slow buildup of the Italian or Ruy Lopez, White strikes in the center immediately, aiming to open the position and use quick development to generate an initiative.", "arrow": {"from": "d2", "to": "d4"}}, {"san": "exd4", "who": "black", "explanation": "Captures, following standard principles of accepting the central challenge."}, {"san": "Nxd4", "who": "white", "explanation": "Recaptures, centralizing the knight with active potential."}, {"san": "Nf6", "who": "black", "explanation": "Develops and attacks e4, a natural, testing response."}, {"san": "Nc3", "who": "white", "explanation": "Defends e4 and develops, keeping the position solid while staying active."}, {"san": "Bb4", "who": "black", "explanation": "Pins the knight, adding pressure and keeping options flexible for central play."}, {"san": "Nxc6", "who": "white", "explanation": "Trades in the center, following through on the plan of simplifying while maintaining an edge in development."}, {"san": "bxc6", "who": "black", "explanation": "Recaptures toward the center, accepting doubled pawns but gaining the bishop pair and open lines for pieces."}, {"san": "Bd3", "who": "white", "explanation": "Develops actively, aiming at the kingside and preparing to castle quickly."}, {"san": "d5", "who": "black", "explanation": "Strikes back in the center immediately, using the open lines and bishop pair for active counterplay."}, {"san": "exd5", "who": "white", "explanation": "Accepts, keeping the extra central pawn for now."}, {"san": "cxd5", "who": "black", "explanation": "Recaptures, maintaining a solid, active position with the bishop pair fully compensating for the doubled pawns. From here, the position is roughly balanced but full of dynamic potential - both sides have chances based on piece activity, and the game rewards accurate calculation over memorized theory."}]}}},scandinavian:{"id": "scandinavian", "name": "Scandinavian Defense", "color": "black", "variations": {"modern_main": {"name": "Modern Main Line", "intro": "The Scandinavian Defense challenges the center on move one, aiming to simplify the position quickly and reach a solid, easy-to-understand middlegame. It's an excellent choice for players who want a sound, low-theory response to 1.e4.", "moves": [{"san": "e4", "who": "white", "explanation": "Central control."}, {"san": "d5", "who": "black", "explanation": "The Scandinavian Defense! Black challenges the center immediately, aiming to simplify and reach a solid, easy-to-understand position - a great choice for players who dislike memorizing long forcing lines."}, {"san": "exd5", "who": "white", "explanation": "Accepts, the natural, principled response."}, {"san": "Qxd5", "who": "black", "explanation": "The Modern Main Line - Black recaptures with the queen right away, accepting a small loss of time in exchange for simplicity and a clear plan."}, {"san": "Nc3", "who": "white", "explanation": "Develops with tempo, attacking the queen and forcing Black to move it again."}, {"san": "Qa5", "who": "black", "explanation": "Retreats to a safe, active square, keeping the queen useful while eyeing a future pin on c3 with a bishop."}, {"san": "d4", "who": "white", "explanation": "Takes full central control, a natural follow-up now that development is ahead."}, {"san": "Nf6", "who": "black", "explanation": "Develops, adding pressure on e4 and preparing to castle."}, {"san": "Nf3", "who": "white", "explanation": "Develops naturally, preparing to castle and adding central control."}, {"san": "Bf5", "who": "black", "explanation": "Develops the light-squared bishop actively before it can be blocked in, similar in spirit to the Caro-Kann's key idea.", "arrow": {"from": "c8", "to": "f5"}}, {"san": "Bd2", "who": "white", "explanation": "A flexible developing move, preparing to castle queenside and adding a defender to c3 in case of a future pin."}, {"san": "e6", "who": "black", "explanation": "Solidifies the position and opens the path for the dark-squared bishop's development."}, {"san": "Nd5", "who": "white", "explanation": "A thematic central outpost, offering a trade of pieces and adding pressure on Black's position."}, {"san": "Qd8", "who": "black", "explanation": "Retreats to safety, avoiding any further tactical complications and keeping development on track. From here, both sides complete development and the game becomes a balanced, strategic middlegame - White has a small development lead from the early queen moves, while Black's position is very solid and easy to play, with no glaring weaknesses."}]}}}};
